const fs = require('fs');
const src = fs.readFileSync('app/dashboard.tsx','utf8');

// Extract dashboardJS string
const jsStart = src.indexOf(\"const dashboardJS = \\\`\");
const jsEnd = src.indexOf('\\\`;\n', jsStart + 22);
const jsContent = src.substring(jsStart + 21, jsEnd);

// Check for unescaped template literal issues
const backtickCount = (jsContent.match(/\\\`/g)||[]).length;
console.log('dashboardJS length:', jsContent.length);
console.log('Backtick count inside:', backtickCount);

// Try to parse it
try {
  new Function(jsContent);
  console.log('JS PARSES OK');
} catch(e) {
  console.log('JS PARSE ERROR:', e.message);
  // Find the line
  const lines = jsContent.split('\n');
  const match = e.message.match(/position (\d+)/);
  if(match) {
    let pos = parseInt(match[1]), line=0, col=0;
    for(let i=0;i<lines.length;i++){
      if(pos<=lines[i].length){line=i;col=pos;break;}
      pos-=lines[i].length+1;
    }
    console.log('Near line', line, 'col', col);
    console.log('Context:', lines[line]?.substring(Math.max(0,col-40), col+40));
  }
}
"

