/* NEWS RIBBON */
.news-ribbon{height:24px;background:#000;border-bottom:1px solid var(--rule);overflow:hidden;position:relative;}
.news-ribbon-inner{display:flex;gap:40px;align-items:center;height:100%;white-space:nowrap;animation:scrollNews 60s linear infinite;position:absolute;padding-left:100%;}
.news-ribbon-inner:hover{animation-play-state:paused;}
.news-item{font-size:10px;font-family:'IBM Plex Mono',monospace;color:var(--t2);display:flex;align-items:center;gap:6px;}
.news-item a{color:var(--blue);text-decoration:none;transition:color .15s;}
.news-item a:hover{color:var(--amber);}
.news-time{color:var(--t4);font-size:9px;}
.news-tag{color:var(--amber);font-weight:600;font-size:9px;letter-spacing:.3px;}
@keyframes scrollNews{0%{transform:translateX(0);}100%{transform:translateX(-100%);}}

@media(max-width:900px){.sidebar{display:none;}.page{flex-direction:column;height:auto;}.main{overflow:visible;}}
@media(max-width:768px){.kpi-strip{grid-template-columns:repeat(2,1fr);}.r2,.r64,.r73,.r37{grid-template-columns:1fr;}.sc-row{grid-template-columns:1fr;}.src-grid{grid-template-columns:1fr;}.ticker{display:none;}.news-ribbon{display:none;}}
</style>

mapObs.observe(document.getElementById('mapContainer'));

// ---- LIVE DATA FETCH ----
(async function(){
  // Fetch live prices
  try {
    const r=await fetch('/api/prices');
    if(r.ok){
      const d=await r.json();
      const fmt=n=>n.toFixed(2);
      const sign=n=>n>=0?'+':'';
      const cls=n=>n>=0?'t-up':'t-dn';
      // Update ticker
      const ticks=document.querySelectorAll('.tick');
      if(ticks[0]){
        ticks[0].querySelector('.tick-v').textContent='$'+fmt(d.brent.price);
        const c=ticks[0].querySelector('.tick-c');c.textContent=sign(d.brent.changePct)+fmt(d.brent.changePct)+'%';c.className='tick-c '+cls(d.brent.changePct);
      }
      if(ticks[2]){
        ticks[2].querySelector('.tick-v').textContent='$'+fmt(d.wti.price);
        const c=ticks[2].querySelector('.tick-c');c.textContent=sign(d.wti.changePct)+fmt(d.wti.changePct)+'%';c.className='tick-c '+cls(d.wti.changePct);
      }
      // Update KPI
      const kpis=document.querySelectorAll('.kpi');
      if(kpis[1]){
        kpis[1].querySelector('.kpi-v').innerHTML='$'+Math.floor(d.brent.price)+'<span style="font-size:11px">.'+fmt(d.brent.price).split('.')[1]+'</span>';
        const sub=kpis[1].querySelector('.kpi-c');sub.textContent=sign(d.brent.changePct)+fmt(d.brent.changePct)+'% today';sub.className='kpi-c '+cls(d.brent.changePct);
      }
      // Update timestamp
      const ts=document.querySelector('.topbar span:last-child');
      if(ts)ts.textContent=new Date(d.timestamp).toLocaleString('en-US',{month:'short',day:'numeric',year:'numeric',hour:'2-digit',minute:'2-digit',timeZoneName:'short'});
    }
  }catch(e){console.log('Price fetch failed:',e);}

  // Fetch news
  try {
    const r=await fetch('/api/news');
    if(r.ok){
      const news=await r.json();
      const ribbon=document.getElementById('newsRibbon');
      if(ribbon&&news.length){
        ribbon.innerHTML=news.map(function(item){
          const d=new Date(item.pubDate);
          const ago=Math.floor((Date.now()-d.getTime())/3600000);
          const time=ago<1?'Just now':ago<24?ago+'h ago':Math.floor(ago/24)+'d ago';
          return '<span class="news-item"><span class="news-tag">NEWS</span><span class="news-time">'+time+'</span><a href="'+item.link+'" target="_blank">'+item.title+'</a></span>';
        }).join('')+'&nbsp;&nbsp;&nbsp;&nbsp;'+news.map(function(item){
          var d=new Date(item.pubDate);var ago=Math.floor((Date.now()-d.getTime())/3600000);
          var time=ago<1?'Just now':ago<24?ago+'h ago':Math.floor(ago/24)+'d ago';
          return '<span class="news-item"><span class="news-tag">NEWS</span><span class="news-time">'+time+'</span><a href="'+item.link+'" target="_blank">'+item.title+'</a></span>';
        }).join('');
      }
    }
  }catch(e){console.log('News fetch failed:',e);}
})();
</script>
</body>
</html>

